+    it('should send an email when status changes to delivered', async () => {
+      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.subject).toContain('Order Delivered');
