+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed', 'order-42'));
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.htmlBody).toContain('order-42');
+      expect(email.textBody).toContain('order-42');
+    });
+
+    it('should send to the order userId', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+
+      expect(handler.getSentEmails()[0]?.to).toBe('user-1');
+    });
+  });
