+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+      expect(handler.getSentCount()).toBe(1);
+
+      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
+      expect(handler.getSentCount()).toBe(2);
+    });
+
+    it('should filter emails by recipient', async () => {
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(handler.getEmailsTo('alice@example.com')).toHaveLength(1);
+      expect(handler.getEmailsTo('bob@example.com')).toHaveLength(0);
+    });
+
+    it('should clear emails', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+      handler.clearEmails();
+      expect(handler.getSentCount()).toBe(0);
+    });
+  });
+
+  describe('integration with EventBus', () => {
+    it('should handle the full order lifecycle via EventBus', async () => {
+      await eventBus.emit(makeOrderCreatedEvent());
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
+      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));
+
+      const emails = handler.getSentEmails();
+      expect(emails).toHaveLength(4);
+      expect(emails[0]?.subject).toContain('Order Confirmation');
+      expect(emails[1]?.subject).toContain('Order Confirmed');
+      expect(emails[2]?.subject).toContain('Order Shipped');
+      expect(emails[3]?.subject).toContain('Order Delivered');
+    });
+
+    it('should coexist with NotificationService on the same EventBus', async () => {
+      // Import NotificationService to verify both can subscribe
+      const { NotificationService, resetNotificationIdCounter } = await import(
+        '../../src/services/notification.service.js'
+      );
+      resetNotificationIdCounter();
+      const notifService = new NotificationService(eventBus);
+
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+
+      // Both handlers should have processed the event
+      expect(handler.getSentCount()).toBe(1);
+      expect(notifService.getNotificationCount()).toBe(1);
+    });
+
+    it('should log events in the EventBus event log', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+
+      const log = eventBus.getEventLog();
+      expect(log).toHaveLength(1);
+      expect(log[0]?.type).toBe('order:status-changed');
+    });
+  });
+});

