/**
 * Email notification handler — formats and dispatches email notifications
 * for order lifecycle events.
 *
 * Subscribes to EventBus events following the same pattern as NotificationService.
 * In production, the `sendEmail` method would integrate with an SMTP service
 * or email API; here it stores emails in memory for testing.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Order Received',
  confirmed: 'Order Confirmed',
  shipped: 'Order Shipped',
  delivered: 'Order Delivered',
  cancelled: 'Order Cancelled',
};

function formatStatusEmailHtml(
  orderId: string,
  previousStatus: string,
  newStatus: string,
): string {
  const label = STATUS_LABELS[newStatus as OrderStatus] ?? newStatus;
  return [
    `<h1>${label}</h1>`,
    `<p>Your order <strong>${orderId}</strong> has been updated.</p>`,
    `<p>Status changed from <em>${previousStatus}</em> to <em>${newStatus}</em>.</p>`,
  ].join('\n');
}

function formatStatusEmailText(
  orderId: string,
  previousStatus: string,
  newStatus: string,
): string {
  const label = STATUS_LABELS[newStatus as OrderStatus] ?? newStatus;
  return `${label}\n\nYour order ${orderId} has been updated.\nStatus changed from ${previousStatus} to ${newStatus}.`;
}

function formatOrderCreatedHtml(event: OrderCreatedEvent): string {
  const itemRows = event.order.items
    .map((item) => `<li>${item.name} x${item.quantity} — $${(item.unitPrice * item.quantity).toFixed(2)}</li>`)
    .join('\n');

  return [
    '<h1>Order Confirmation</h1>',
    `<p>Thank you for your order, ${event.user.name}!</p>`,
    `<p>Order ID: <strong>${event.order.id}</strong></p>`,
    '<ul>',
    itemRows,
    '</ul>',
    `<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`,
  ].join('\n');
}

function formatOrderCreatedText(event: OrderCreatedEvent): string {
  const itemLines = event.order.items
    .map((item) => `- ${item.name} x${item.quantity} — $${(item.unitPrice * item.quantity).toFixed(2)}`)
    .join('\n');

  return `Order Confirmation\n\nThank you for your order, ${event.user.name}!\nOrder ID: ${event.order.id}\n\n${itemLines}\n\nTotal: $${event.order.total.toFixed(2)}`;
}

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers for email notifications.
   * All handlers subscribe via EventBus.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation — ${event.order.id}`,
      htmlBody: formatOrderCreatedHtml(event),
      textBody: formatOrderCreatedText(event),
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const label = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
    this.logger.info(
      `Sending status email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendEmail({
      to: event.order.userId,
      subject: `${label} — ${event.order.id}`,
      htmlBody: formatStatusEmailHtml(event.order.id, event.previousStatus, event.newStatus),
      textBody: formatStatusEmailText(event.order.id, event.previousStatus, event.newStatus),
    });
  }

  /**
   * Send an email (in-memory for this demo).
   * In production, this would call an SMTP/email API.
   */
  private sendEmail(params: Omit<EmailMessage, 'sentAt'>): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get emails sent to a specific address.
   */
  getEmailsTo(address: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === address);
  }

  /**
   * Get the count of sent emails.
   */
  getSentCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

